PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "params" (
"seed" INTEGER
);
CREATE TABLE IF NOT EXISTS "sites" (
"site" TEXT,
  "lon" REAL,
  "lat" REAL
);
CREATE TABLE IF NOT EXISTS "surveys" (
"label" INTEGER,
  "site" TEXT,
  "date" TEXT
);
CREATE TABLE IF NOT EXISTS "samples" (
"label" INTEGER,
  "lon" REAL,
  "lat" REAL,
  "reading" REAL
);
COMMIT;
